param([string]$StatePath="ENGREMIAT_MEMORY/operative/dashboard/dashboard-state.json",[string]$HtmlPath="ENGREMIAT_MEMORY/dashboard/memory/index.html",[string]$ReportPath="reports/dev-visual-memory-operative/e03-operative-dashboard/visual-dashboard-smoke-report.json")
$ErrorActionPreference="Stop"
[Console]::OutputEncoding=[System.Text.Encoding]::UTF8
function ED($p){if($p -and !(Test-Path -LiteralPath $p)){New-Item -ItemType Directory -Path $p -Force|Out-Null}}
function WJ($p,$o){ED(Split-Path -Parent $p);$o|ConvertTo-Json -Depth 100|Set-Content -LiteralPath $p -Encoding UTF8}
$missing=@();if(!(Test-Path -LiteralPath $StatePath -PathType Leaf)){$missing+=$StatePath};if(!(Test-Path -LiteralPath $HtmlPath -PathType Leaf)){$missing+=$HtmlPath};$stateOk=$false;$htmlOk=$false;$events=0;$gates=0;$arts=0;if($missing.Count -eq 0){$st=Get-Content -LiteralPath $StatePath -Raw -Encoding UTF8|ConvertFrom-Json;$events=[int]$st.events_count;$gates=[int]$st.gates_count;$arts=[int]$st.artifacts_count;$stateOk=($st.objective_id -and $st.next -and $st.maps.Count -gt 0);$html=Get-Content -LiteralPath $HtmlPath -Raw -Encoding UTF8;$htmlOk=($html -match "ENGREMIAT Visual Memory Operative" -and $html -match "Últimos OK" -and $html -match "Mapas y navegación" -and $html -match "Comandos esperados")}
$ok=($missing.Count -eq 0 -and $stateOk -and $htmlOk);$rep=[ordered]@{objective_id="ENGREMIAT_DEV_VISUAL_MEMORY_OPERATIVE_002";stage_id="E03";step_id="P03.3.2";status=$(if($ok){"OK"}else{"NO_GO"});validation_passed=$ok;missing=$missing;state_ok=$stateOk;html_ok=$htmlOk;events_count=$events;gates_count=$gates;artifacts_count=$arts;state=$StatePath;html=$HtmlPath;checked_at=(Get-Date).ToString("s")};WJ $ReportPath $rep;if(-not $ok){Write-Host ("ERR visual_dashboard=False missing="+($missing -join ","));exit 1};Write-Host ("OK visual_dashboard=True events="+$events+" gates="+$gates+" artifacts="+$arts+" report="+$ReportPath)
